        return any(int(digit) % 2 == 0 for digit in str(num))

    return sorted(set(filter(lambda num: not has_even_digit(num), x)))

def exchange(lst1, lst2):
    # Count the number of odd numbers in lst1
    odd_count_lst1 = sum(1 for num in lst1 if num % 2 != 0)

    # Count the number of even numbers in lst2
    even_count_lst2 = sum(1 for num in lst2 if num % 2 == 0)

    # Check if there are enough even numbers in lst2 to exchange with all odd numbers in lst1
    if even_count_lst2 >= odd_count_lst1:
        return "YES"
    else:
        return "NO"

def choose_num(x, y):
    if x > y:
        return -1
    if y % 2 == 0:
        return y
    if y - 1 >= x:
        return y - 1
    return -1

