def tri(n):
    result = []
    for i in range(n + 1):
        if i == 0:
            result.append(1)
        elif i == 1:
            result.append(3)
        elif i % 2 == 0:
            result.append(1 + i // 2)
        else:
            result.append(result[i - 1] + result[i - 2] + (1 + (i + 1) // 2))
    return result

def is_sorted(lst):
    counts = {}
    for i, num in enumerate(lst):
        if i > 0 and lst[i - 1] > num:
            return False
        counts[num] = counts.get(num, 0) + 1
        if counts[num] > 2:
            return False
    return True

def fix_spaces(text):
    result = []
    i = 0
    while i < len(text):
        if text[i] == " ":
            j = i
            while j < len(text) and text[j] == " ":
                j += 1
            count = j - i
            if count > 2:
                result.append("-")
            else:
                result.append("_" * count)
            i = j
        else:
            result.append(text[i])
            i += 1
    return "".join(result)

def is_nested(string):
    opens = 0
    closes_after = string.count(']')

    for char in string:
        if char == '[':
            opens += 1
        else:
            closes_after -= 1
            if opens >= 2 and closes_after >= 1:
                return True

    return False

import math

def is_prime(num):
    """Check if a number is prime."""
    if num <= 1:
        return False
    if num <= 3:
        return True
    if num % 2 == 0 or num % 3 == 0:
        return False
    i = 5
    while i * i <= num:
        if num % i == 0 or num % (i + 2) == 0:
            return False
        i += 6
    return True

def x_or_y(n, x, y):
    """Return x if n is a prime number, else return y."""
    return x if is_prime(n) else y

def x_or_y(n, x, y):
    """A simple program which should return the value of x if n is 
    a prime number and should return the value of y otherwise.

    Examples:
    for x_or_y(7, 34, 12) == 34
    for x_or_y(15, 8, 5) == 5

    """
    if n < 2:
        return y
    if n == 2:
        return x
    if n % 2 == 0:
        return y
    i = 3
    while i * i <= n:
        if n % i == 0:
            return y
        i += 2
    return x

def sum_squares(lst):
